// Extract video ID from a single YouTube URL
const videoUrl = $input.first().json['Video URL'];
const maxComments = $input.first().json['Max Comments to Process'] || 10;

let videoId = '';

// Handle different possible YouTube URL types
if (videoUrl.includes('youtube.com/watch?v=')) {
  // Example: https://www.youtube.com/watch?v=Aw7IjqKAX2k
  videoId = videoUrl.split('v=')[1].split('&')[0];
} else if (videoUrl.includes('youtu.be/')) {
  // Example: https://youtu.be/Aw7IjqKAX2k
  videoId = videoUrl.split('youtu.be/')[1].split('?')[0];
} else if (videoUrl.includes('youtube.com/embed/')) {
  // Example: https://www.youtube.com/embed/Aw7IjqKAX2k
  videoId = videoUrl.split('/embed/')[1].split('?')[0];
} else if (videoUrl.includes('youtube.com/v/')) {
  // Example: https://www.youtube.com/v/Aw7IjqKAX2k
  videoId = videoUrl.split('/v/')[1].split('?')[0];
} else {
  // Assume user directly provided the video ID
  videoId = videoUrl.trim();
}

// Clean up possible extra parameters
videoId = videoId.split('&')[0].split('#')[0];

// ✅ Return a single structured JSON object
return [{
  json: {
    videoId,
    videoUrl: `https://www.youtube.com/watch?v=${videoId}`,
    maxComments,
    inputType: 'Direct Link'
  }
}];

// Get video data from API response
const response = $input.first().json;
const videoData = response.items && response.items[0];
const prevData = $('Extract Video ID from URL').first().json;

if (!videoData) {
  throw new Error('Video not found. Please check the URL.');
}

const stats = videoData.statistics;
const snippet = videoData.snippet;

return [{
  json: {
    items: videoData,
    videoId: videoData.id,
    videoUrl: prevData.videoUrl,
    maxComments: prevData.maxComments,
    viewCount: parseInt(stats.viewCount || 0),
    engagementScore: parseInt(stats.likeCount || 0) + parseInt(stats.commentCount || 0),
    selectionType: 'Direct Link Input'
  }
}];

// Get the items array from the Extract Comments node
const commentsData = $input.first().json.items;

// Create an array to hold individual comment items
const outputItems = [];

// Loop through each comment in the items array
for (let i = 0; i < commentsData.length; i++) {
  const comment = commentsData[i];

  // Create an output item for each comment with its details
  outputItems.push({
    json: {
      commentId: comment.snippet.topLevelComment.id,
      textDisplay: comment.snippet.topLevelComment.snippet.textDisplay,
      textOriginal: comment.snippet.topLevelComment.snippet.textOriginal,
      authorDisplayName: comment.snippet.topLevelComment.snippet.authorDisplayName,
      authorChannelUrl: comment.snippet.topLevelComment.snippet.authorChannelUrl,
      videoId: comment.snippet.videoId,
      channelId: comment.snippet.channelId,
      likeCount: comment.snippet.topLevelComment.snippet.likeCount,
      publishedAt: comment.snippet.topLevelComment.snippet.publishedAt,
      canReply: comment.snippet.canReply,
      totalReplyCount: comment.snippet.totalReplyCount
    }
  });
}

// Return all comment items
return outputItems;

// Get all comment items from the input
const comments = $input.all().map(item => item.json);

// Sort by newest (publishedAt descending)
const newestComments = [...comments].sort((a, b) => {
  return new Date(b.publishedAt) - new Date(a.publishedAt);
}).slice(0, 5);

// Calculate engagement score and sort by it
const commentsByEngagement = [...comments].map(comment => ({
  ...comment,
  engagementScore: (comment.likeCount || 0) + (comment.totalReplyCount || 0)
})).sort((a, b) => b.engagementScore - a.engagementScore);

// Get top 5 by engagement
const topEngagementComments = commentsByEngagement.slice(0, 5);

// Combine and remove duplicates based on commentId
const selectedComments = [...newestComments];
const selectedIds = new Set(newestComments.map(c => c.commentId));

for (const comment of topEngagementComments) {
  if (!selectedIds.has(comment.commentId)) {
    selectedComments.push(comment);
    selectedIds.add(comment.commentId);
  }
}

// Return as n8n items
return selectedComments.map(comment => ({
  json: comment
}));

